// src/pages/SignUp.js
import React, { useState } from "react";
import { Link } from "react-router-dom";

const initial = { name: "", email: "", password: "" };

const validPassword = (p) =>
  p.length >= 8 && /[A-Z]/.test(p) && /\d/.test(p); // 8+ chars, 1 uppercase, 1 number

export default function SignUp({ onSignUp }) {
  const [form, setForm] = useState(initial);
  const [showPwd, setShowPwd] = useState(false);
  const [errors, setErrors] = useState({});

  const update = (e) => {
    const { name, value } = e.target;
    setForm((f) => ({ ...f, [name]: value }));
  };

  const submit = async (e) => {
    e.preventDefault();
    const next = {};
    if (!form.name.trim()) next.name = "Name is required";
    if (!form.email.trim()) next.email = "Email is required";
    if (!validPassword(form.password))
      next.password = "Use 8+ chars with 1 uppercase letter and 1 number";
    setErrors(next);
    if (Object.keys(next).length) return;

    // TODO: replace with API call
    await new Promise((r) => setTimeout(r, 500));
    onSignUp && onSignUp({ name: form.name, email: form.email });
  };

  return (
    <div className="g-auth-bg">
      <div className="g-auth-card">
        <div className="g-auth-logo">
          <span className="g-dot g-blue" />
          <span className="g-dot g-red" />
          <span className="g-dot g-yellow" />
          <span className="g-dot g-green" />
          <span className="g-brand">NeuroFleetX</span>
        </div>

        <h1 className="g-title">Sign up</h1>
        <p className="g-subtitle">Create an account</p>

        <form className="g-form" onSubmit={submit}>
          <div className="g-field">
            <input
              className="g-input"
              name="name"
              placeholder="Name"
              value={form.name}
              onChange={update}
              autoComplete="name"
              required
            />
            {errors.name && <div className="g-error">{errors.name}</div>}
          </div>

          <div className="g-field">
            <input
              className="g-input"
              type="email"
              name="email"
              placeholder="Email"
              value={form.email}
              onChange={update}
              autoComplete="email"
              required
            />
            {errors.email && <div className="g-error">{errors.email}</div>}
          </div>

          <div className="g-field" style={{ position: "relative" }}>
            <input
              className="g-input"
              type={showPwd ? "text" : "password"}
              name="password"
              placeholder="Password (8+ chars, 1 uppercase, 1 number)"
              value={form.password}
              onChange={update}
              autoComplete="new-password"
              required
            />
            <button
              type="button"
              onClick={() => setShowPwd((v) => !v)}
              aria-label="Toggle password visibility"
              style={{
                position: "absolute",
                right: 10,
                top: 8,
                background: "none",
                border: "none",
                color: "#1a73e8",
                cursor: "pointer",
              }}
            >
              {showPwd ? "Hide" : "Show"}
            </button>
            {errors.password && <div className="g-error">{errors.password}</div>}
          </div>

          <div className="g-actions">
            <button className="g-btn" type="submit">Create account</button>
          </div>
        </form>

        <div className="g-help">
          <Link to="/">Already have an account? Sign in</Link>
        </div>
      </div>
    </div>
  );
}
